const $=id=>document.getElementById(id);const KEY='rus_receipt_central_v1',ROOT='receipt_app_main';
const BRAND_LOGO_DATA = 'data:image/png;base64,';
let mode='user',me=null,page='receipt',cloud=null,hydrated=false;
const base={admin:{username:'admin',password:'9999'},users:[],receipts:[],counter:0,settings:{org:'มหาวิทยาลัยเทคโนโลยีราชมงคลสุวรรณภูมิ',addr:'ศูนย์พระนครศรีอยุธยา หันตรา เลขที่ 60 หมู่ 3 ถนนสายเอเซีย ต.หันตรา อ.พระนครศรีอยุธยา จ.พระนครศรีอยุธยา 13000',receiver:'เจ้าหน้าที่ผู้รับชำระเงิน'},titles:['นาย','นาง','นางสาว','ดร.','อื่นๆ'],items:['ค่าลงทะเบียน','ค่าธรรมเนียม','ค่าบำรุงการศึกษา'],projects:['ไม่ระบุโครงการ','โครงการบริการวิชาการ'],books:[{bookNo:'2569-001',start:1,end:500,latest:0,active:true}]};
let db=norm(loadLocal());function clone(o){return JSON.parse(JSON.stringify(o))}function norm(x){x={...clone(base),...(x||{})};x.admin={...base.admin,...(x.admin||{})};x.settings={...base.settings,...(x.settings||{})};x.users=(x.users||[]).map(u=>({code:String(u.code||''),name:u.name||'',active:u.active!==false}));x.receipts=x.receipts||[];x.items=x.items&&x.items.length?x.items:base.items;x.projects=x.projects&&x.projects.length?x.projects:base.projects;x.books=x.books&&x.books.length?x.books:base.books;return x}function loadLocal(){try{return JSON.parse(localStorage.getItem(KEY)||'null')||clone(base)}catch{return clone(base)}}function saveLocal(){localStorage.setItem(KEY,JSON.stringify(db))}function esc(v){return String(v??'').replace(/[&<>'"]/g,m=>({'&':'&amp;','<':'&lt;','>':'&gt;',"'":'&#39;','"':'&quot;'}[m]))}function money(n){return Number(n||0).toLocaleString('th-TH',{minimumFractionDigits:2,maximumFractionDigits:2})}function today(){return new Date().toISOString().slice(0,10)}function nowTime(){return new Date().toTimeString().slice(0,5)}function rid(){return'D'+Date.now().toString(36)+Math.random().toString(36).slice(2,7)}
function setStatus(t,local=false){$('dbStatus').textContent=t;$('dbStatus').classList.toggle('local',local)}async function save(){saveLocal();if(cloud&&hydrated){await cloud.set(db)}}
function initCloud(){try{const cfg=window.APP_FIREBASE_CONFIG||window.firebaseConfig;if(!window.firebase||!cfg||!cfg.apiKey)return setStatus('Local Browser',true);firebase.initializeApp(cfg);cloud=firebase.database().ref(ROOT);cloud.on('value',s=>{const v=s.val();if(v){db=norm(v);saveLocal();if(me)draw()}else{cloud.set(db)}hydrated=true;setStatus('ฐานข้อมูลกลางเชื่อมต่อแล้ว')});}catch(e){console.error(e);setStatus('Local Browser',true)}}
function applyBrandLogo(){const img=$('brandLogo');if(img) img.src=BRAND_LOGO_DATA;}
$('chooseAdmin').onclick=()=>{mode='admin';$('adminFields').classList.remove('hidden');$('userFields').classList.add('hidden');$('loginHint').textContent='Username: admin / Password: 9999'};$('chooseUser').onclick=()=>{mode='user';$('adminFields').classList.add('hidden');$('userFields').classList.remove('hidden');$('loginHint').textContent='กรอกรหัส 4 หลักที่ Admin กำหนดให้'};
$('loginForm').onsubmit=e=>{e.preventDefault();if(mode==='admin'){if($('adminUser').value.trim()===db.admin.username&&$('adminPass').value===db.admin.password){me={role:'admin',name:'ผู้ดูแลระบบ'};page='dash';enter()}else alert('Username หรือ Password ไม่ถูกต้อง');return}const code=$('userCode').value.trim(),u=db.users.find(x=>x.code===code);if(!/^\d{4}$/.test(code))return alert('กรุณากรอกรหัส 4 หลัก');if(!u)return alert('รหัสนี้ยังไม่ได้สร้างโดย Admin');if(!u.active)return alert('User นี้ถูกปิดใช้งาน');me={role:'user',name:u.name,code:u.code};page='receipt';enter()};$('logout').onclick=()=>{me=null;$('app').classList.add('hidden');$('login').classList.remove('hidden')};
function enter(){$('login').classList.add('hidden');$('app').classList.remove('hidden');$('who').textContent=me.name;$('roleLabel').textContent=me.role;drawNav();draw()}
function drawNav(){const a=me.role==='admin'?[['dash','หน้าหลัก'],['users','ผู้ใช้งาน'],['receipt','ออกใบเสร็จ'],['list','ใบเสร็จ'],['settings','ตั้งค่า'],['data','ฐานข้อมูล']]:[['receipt','ออกใบเสร็จ']];$('nav').innerHTML=a.map(x=>`<button class="${page===x[0]?'active':''}" data-p="${x[0]}">${x[1]}</button>`).join('');document.querySelectorAll('#nav button').forEach(b=>b.onclick=()=>{page=b.dataset.p;drawNav();draw()})}
function draw(){const title={dash:'หน้าหลัก',users:'จัดการ User',receipt:'บันทึกรายการชำระเงิน',list:'รายการใบเสร็จ',settings:'ตั้งค่าระบบ',data:'ฐานข้อมูล'}[page];$('pageTitle').textContent=title;$('content').innerHTML=views[page]();bind()}
const views={dash(){const ok=db.receipts.filter(r=>r.status!=='ยกเลิก'),sum=ok.reduce((a,r)=>a+Number(r.total),0);return `<div class="grid four"><div class="stat"><span>ใบเสร็จทั้งหมด</span><b>${db.receipts.length}</b></div><div class="stat"><span>ปกติ</span><b>${ok.length}</b></div><div class="stat"><span>ยกเลิก</span><b>${db.receipts.length-ok.length}</b></div><div class="stat"><span>ยอดรับสุทธิ</span><b>${money(sum)}</b></div></div><div class="card"><h3>ใบเสร็จล่าสุด</h3>${table(db.receipts.slice(-8).reverse())}</div>`},users(){return `<div class="card"><h3>เพิ่ม User</h3><div class="grid three"><label>รหัส 4 หลัก<input id="uc" maxlength="4" inputmode="numeric"></label><label>ชื่อผู้ใช้งาน<input id="un"></label><label>&nbsp;<button id="addUser" class="btn green" type="button">เพิ่ม User</button></label></div></div><div class="card table"><table><tr><th>รหัส</th><th>ชื่อ</th><th>สถานะ</th><th></th></tr>${db.users.map((u,i)=>`<tr><td>${u.code}</td><td>${esc(u.name)}</td><td>${u.active?'ใช้งาน':'ปิด'}</td><td class="actions"><button data-toggle="${i}" class="btn light" type="button">${u.active?'ปิด':'เปิด'}</button><button data-deluser="${i}" class="btn red" type="button">ลบ</button></td></tr>`).join('')}</table></div>`},receipt(){return `<form id="receiptForm" class="card"><div class="grid four"><label>วันที่<input id="rDate" type="date" value="${today()}"></label><label>เวลา<input id="rTime" type="time" value="${nowTime()}"></label><label>ประเภท<select id="payerType"><option>บุคคล</option><option>หน่วยงาน</option></select></label><label>ช่องทาง<select id="payMethod"><option>เงินสด</option><option>เงินโอน</option></select></label></div><div class="grid three"><label>คำนำหน้า<select id="titleSel">${db.titles.map(x=>`<option>${esc(x)}</option>`)}</select></label><label>ชื่อ/หน่วยงาน<input id="firstName" required></label><label>นามสกุล<input id="lastName"></label></div><div class="grid two"><label>รายละเอียดบรรทัดที่ 1<input id="detail1"></label><label>รายละเอียดบรรทัดที่ 2<input id="detail2"></label></div><h3>รายการชำระเงิน</h3><div class="grid three"><label>รายการ<select id="itemSel">${db.items.map(x=>`<option>${esc(x)}</option>`)}</select></label><label>โครงการ<select id="projectSel">${db.projects.map(x=>`<option>${esc(x)}</option>`)}</select></label><label>จำนวนเงิน<input id="amount" type="number" min="0" step="0.01" value="0"></label></div><div class="total" id="totalLabel">0.00 บาท</div><div class="bar"><button type="reset" class="btn light">ล้างฟอร์ม</button><button class="btn green">บันทึกและพิมพ์ใบเสร็จ</button></div></form>`},list(){return `<div class="card table">${table(db.receipts.slice().reverse())}</div>`},settings(){return `<div class="card"><div class="grid two"><label>ชื่อมหาวิทยาลัย<input id="org" value="${esc(db.settings.org)}"></label><label>ตำแหน่งผู้รับเงิน<input id="receiver" value="${esc(db.settings.receiver)}"></label></div><label>ที่อยู่<textarea id="addr">${esc(db.settings.addr)}</textarea></label><div class="grid two"><label>Admin Username<input id="setAdmin" value="${esc(db.admin.username)}"></label><label>Admin Password<input id="setPass" value="${esc(db.admin.password)}"></label></div><button id="saveSettings" class="btn green" type="button">บันทึกตั้งค่า</button></div>`},data(){return `<div class="card"><p>สถานะ: <b>${cloud?'ฐานข้อมูลกลาง Firebase':'Local Browser'}</b></p><div class="actions"><button id="exportData" class="btn light" type="button">สำรอง JSON</button><label class="btn light">นำเข้า JSON<input id="importData" type="file" accept="application/json" hidden></label></div></div>`}};
function bind(){if(page==='users'){document.querySelector('#addUser').onclick=async()=>{const code=$('uc').value.trim(),name=$('un').value.trim();if(!/^\d{4}$/.test(code))return alert('รหัสต้องเป็นตัวเลข 4 หลัก');if(!name)return alert('กรอกชื่อผู้ใช้งาน');if(db.users.some(u=>u.code===code))return alert('รหัสนี้มีอยู่แล้ว');db.users.push({code,name,active:true});await save();draw()};document.querySelectorAll('[data-toggle]').forEach(b=>b.onclick=async()=>{db.users[b.dataset.toggle].active=!db.users[b.dataset.toggle].active;await save();draw()});document.querySelectorAll('[data-deluser]').forEach(b=>b.onclick=async()=>{if(confirm('ลบ User นี้?')){db.users.splice(b.dataset.deluser,1);await save();draw()}})}if(page==='receipt'){const amt=$('amount'),tl=$('totalLabel');amt.oninput=()=>tl.textContent=money(amt.value)+' บาท';$('receiptForm').onsubmit=async e=>{e.preventDefault();const no=await nextNo();const book=db.books[0]||base.books[0];const r={id:rid(),bookNo:book.bookNo,receiptNo:String(no).padStart(3,'0'),date:$('rDate').value,time:$('rTime').value,payerType:$('payerType').value,title:$('titleSel').value,firstName:$('firstName').value,lastName:$('lastName').value,detail1:$('detail1').value,detail2:$('detail2').value,item:$('itemSel').value,project:$('projectSel').value,method:$('payMethod').value,total:Number($('amount').value||0),user:me.name,status:'ปกติ',createdAt:new Date().toISOString()};db.receipts.push(r);await save();printReceipt(r);draw()}}if(page==='list'){document.querySelectorAll('[data-print]').forEach(b=>b.onclick=()=>printReceipt(db.receipts.find(r=>r.id===b.dataset.print)));document.querySelectorAll('[data-cancel]').forEach(b=>b.onclick=async()=>{const r=db.receipts.find(x=>x.id===b.dataset.cancel);if(r&&confirm('ยกเลิกใบเสร็จนี้?')){r.status='ยกเลิก';await save();draw()}})}if(page==='settings')$('saveSettings').onclick=async()=>{db.settings.org=$('org').value;db.settings.addr=$('addr').value;db.settings.receiver=$('receiver').value;db.admin.username=$('setAdmin').value.trim()||'admin';db.admin.password=$('setPass').value||'9999';await save();alert('บันทึกแล้ว')};if(page==='data'){$('exportData').onclick=()=>download('receipt-backup.json',JSON.stringify(db,null,2));$('importData').onchange=e=>{const f=e.target.files[0];if(!f)return;const rd=new FileReader();rd.onload=async()=>{try{db=norm(JSON.parse(rd.result));await save();draw();alert('นำเข้าแล้ว')}catch{alert('ไฟล์ไม่ถูกต้อง')}};rd.readAsText(f)}}}
async function nextNo(){if(cloud&&hydrated){try{const r=await firebase.database().ref(ROOT+'/counter').transaction(n=>(Number(n)||0)+1);db.counter=r.snapshot.val();return db.counter}catch(e){console.error(e)}}db.counter=Number(db.counter||0)+1;return db.counter}
function table(arr){return `<table><tr><th>เล่ม/เลขที่</th><th>วันที่</th><th>ผู้ชำระ</th><th>รายการ</th><th>ยอด</th><th>สถานะ</th><th></th></tr>${arr.map(r=>`<tr><td>${r.bookNo}/${r.receiptNo}</td><td>${esc(r.date)} ${esc(r.time||'')}</td><td>${esc([r.title,r.firstName,r.lastName].join(' '))}</td><td>${esc(r.item)}<br><small>${esc(r.project||'')}</small></td><td>${money(r.total)}</td><td>${esc(r.status)}</td><td class="actions"><button class="btn light" data-print="${r.id}" type="button">พิมพ์</button>${r.status!=='ยกเลิก'?`<button class="btn red" data-cancel="${r.id}" type="button">ยกเลิก</button>`:''}</td></tr>`).join('')||'<tr><td colspan="7">ยังไม่มีข้อมูล</td></tr>'}</table>`}
function printReceipt(r){if(!r)return;const pageHtml=copy=>`<article class="receipt" style="position:relative;overflow:hidden"><img src="${BRAND_LOGO_DATA}" alt="ลายน้ำ" style="position:absolute;left:50%;top:52%;transform:translate(-50%,-50%);width:72mm;opacity:.08;z-index:0;pointer-events:none;">${r.status==='ยกเลิก'?'<div class="water">ยกเลิก</div>':''}<div style="position:relative;z-index:1"><div class="rhead"><div>เล่มที่ ${esc(r.bookNo)}<br>เลขที่ ${esc(r.receiptNo)}</div><div class="emblems"><img src="garuda.png" alt="ตราครุฑ"></div><div style="text-align:right">วันที่ ${esc(r.date)}</div></div><h2>ใบเสร็จรับเงิน</h2><div class="center"><b>${esc(db.settings.org)}</b><br><small>${esc(db.settings.addr)}</small><br><b>${copy}</b></div><p>ได้รับเงินจาก ${esc([r.title,r.firstName,r.lastName].join(' '))}</p><p>${esc(r.detail1||'')} ${esc(r.detail2||'')}</p><table><tr><th>รายการ</th><th>จำนวนเงิน</th></tr><tr><td>${esc(r.item)}<br>${esc(r.project||'')}</td><td style="text-align:right">${money(r.total)}</td></tr><tr><th>รวมเงิน</th><th style="text-align:right">${money(r.total)}</th></tr></table><br><br><p style="text-align:right">ลงชื่อ __________________ ผู้รับเงิน<br>${esc(db.settings.receiver)}</p></div></article>`;$('printArea').innerHTML=`<div class="no-print"><button class="btn" onclick="window.print()">พิมพ์</button><button class="btn light" onclick="document.getElementById('printArea').style.display='none'">ปิด</button></div>`+pageHtml('ต้นฉบับ')+pageHtml('สำเนา');$('printArea').style.display='block';setTimeout(()=>window.print(),300)}function download(n,c){const a=document.createElement('a');a.href=URL.createObjectURL(new Blob([c],{type:'application/json'}));a.download=n;a.click();setTimeout(()=>URL.revokeObjectURL(a.href),1000)}
applyBrandLogo();
initCloud();saveLocal();
